import React, { useState, useEffect } from 'react';
import { BarChart3 } from 'lucide-react';

const AvaliacoesView = ({ usuario, API_BASE_URL, pacienteSelecionado }) => {
  const [novaAvaliacaoTipo, setNovaAvaliacaoTipo] = useState('PHQ-9');
  const [respostasAvaliacao, setRespostasAvaliacao] = useState({});
  const [listaAvaliacoes, setListaAvaliacoes] = useState([]);
  const [carregandoAvaliacoes, setCarregandoAvaliacoes] = useState(false);

  const fetchAvaliacoes = async () => {
    if (!usuario || !pacienteSelecionado) return;
    setCarregandoAvaliacoes(true);
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteSelecionado.id}/avaliacoes`, {
        headers: { 'Authorization': `Bearer ${usuario.token}` }
      });
      if (resp.ok) {
        const data = await resp.json();
        setListaAvaliacoes(data);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setCarregandoAvaliacoes(false);
    }
  };

  useEffect(() => {
    fetchAvaliacoes();
    setNovaAvaliacaoTipo('PHQ-9');
    setRespostasAvaliacao({});
  }, [pacienteSelecionado, usuario]);

  const handleSalvarAvaliacao = async (escore_total, classificacao) => {
    if (!usuario || !pacienteSelecionado) return;
    try {
      const resp = await fetch(`${API_BASE_URL}/paciente/${pacienteSelecionado.id}/avaliacoes`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${usuario.token}`
        },
        body: JSON.stringify({
          tipo_escala: novaAvaliacaoTipo,
          respostas_json: JSON.stringify(respostasAvaliacao),
          escore_total: escore_total,
          classificacao: classificacao
        })
      });
      const data = await resp.json();
      if (resp.ok) {
        setRespostasAvaliacao({});
        fetchAvaliacoes();
        alert('Avaliação salva com sucesso!');
      } else {
        alert(data.erro);
      }
    } catch (e) {
      console.error(e);
      alert('Erro ao salvar avaliação');
    }
  };

  const phq9Perguntas = [
    "Pouco interesse ou pouco prazer em fazer as coisas",
    "Se sentir para baixo, deprimido ou sem esperança",
    "Problemas para pegar no sono ou manter o sono, ou dormir mais do que o costume",
    "Se sentir cansado ou com pouca energia",
    "Falta de apetite ou comendo demais",
    "Sentir-se mal consigo mesmo, achar que é um fracasso ou que decepcionou sua família ou a você mesmo",
    "Problemas para se concentrar nas coisas (ex: ler jornal, ver TV)",
    "Mover-se ou falar tão devagar que outras pessoas notaram. Ou estar tão agitado/inquieto que você tem se movido mais do que o costume",
    "Pensamentos de que você estaria melhor morto ou de machucar a si mesmo de alguma forma"
  ];

  const gad7Perguntas = [
    "Sentir-se nervoso, ansioso ou muito tenso",
    "Não ser capaz de parar ou controlar a preocupação",
    "Preocupar-se muito com coisas diferentes",
    "Dificuldade para relaxar",
    "Ficar tão agitado que é difícil ficar sentado",
    "Tornar-se facilmente aborrecido ou irritável",
    "Sentir medo como se algo terrível fosse acontecer"
  ];

  const perguntas = novaAvaliacaoTipo === 'PHQ-9' ? phq9Perguntas : gad7Perguntas;
  const opcoes = ["Nenhuma vez", "Vários dias", "Mais da metade dos dias", "Quase todos os dias"];

  const handleOpcaoChange = (index, valor) => {
    setRespostasAvaliacao({ ...respostasAvaliacao, [index]: valor });
  };

  const calcularEscore = () => {
    let total = 0;
    perguntas.forEach((_, i) => {
      if (respostasAvaliacao[i] !== undefined) total += respostasAvaliacao[i];
    });
    return total;
  };

  const classificarEscore = (total) => {
    if (novaAvaliacaoTipo === 'PHQ-9') {
      if (total <= 4) return "Depressão Mínima";
      if (total <= 9) return "Depressão Leve";
      if (total <= 14) return "Depressão Moderada";
      if (total <= 19) return "Depressão Moderadamente Grave";
      return "Depressão Grave";
    } else {
      if (total <= 4) return "Ansiedade Mínima";
      if (total <= 9) return "Ansiedade Leve";
      if (total <= 14) return "Ansiedade Moderada";
      return "Ansiedade Grave";
    }
  };

  return (
    <div className="glass-panel" style={{ padding: '24px', flex: 1, overflowY: 'auto' }}>
      <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <BarChart3 size={24} color="var(--accent)" />
        Avaliações Psicométricas
      </h2>
      <p style={{ color: 'var(--text-secondary)' }}>Aplique e acompanhe escalas padronizadas para monitoramento clínico.</p>

      <div style={{ display: 'flex', gap: '20px', marginTop: '20px' }}>
        <div style={{ flex: 1 }}>
          <div className="glass-card">
            <h3>Nova Avaliação</h3>
            <div style={{ marginBottom: '15px' }}>
              <label>Selecione a Escala:</label>
              <select 
                value={novaAvaliacaoTipo} 
                onChange={(e) => { setNovaAvaliacaoTipo(e.target.value); setRespostasAvaliacao({}); }}
                style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', border: '1px solid var(--glass-border)', background: 'rgba(255,255,255,0.05)', color: 'white' }}
              >
                <option value="PHQ-9">PHQ-9 (Depressão)</option>
                <option value="GAD-7">GAD-7 (Ansiedade)</option>
              </select>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
              {perguntas.map((p, index) => (
                <div key={index} style={{ padding: '10px', background: 'rgba(255,255,255,0.03)', borderRadius: '8px' }}>
                  <p style={{ marginBottom: '10px' }}><strong>{index + 1}.</strong> {p}</p>
                  <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                    {opcoes.map((op, v) => (
                      <label key={v} style={{ display: 'flex', alignItems: 'center', gap: '5px', cursor: 'pointer' }}>
                        <input 
                          type="radio" 
                          name={`pergunta-${index}`} 
                          value={v} 
                          checked={respostasAvaliacao[index] === v}
                          onChange={() => handleOpcaoChange(index, v)}
                        />
                        {op} ({v})
                      </label>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <button 
              className="btn-primary" 
              style={{ width: '100%', marginTop: '20px' }}
              onClick={() => {
                if (Object.keys(respostasAvaliacao).length < perguntas.length) {
                  alert("Por favor, responda a todas as perguntas.");
                  return;
                }
                const score = calcularEscore();
                const cls = classificarEscore(score);
                handleSalvarAvaliacao(score, cls);
              }}
            >
              Salvar e Calcular Escore
            </button>
          </div>
        </div>

        <div style={{ width: '400px' }}>
          <div className="glass-card">
            <h3>Histórico de Avaliações</h3>
            {carregandoAvaliacoes ? <p>Carregando...</p> : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', marginTop: '10px' }}>
                {listaAvaliacoes.length === 0 ? <p style={{ color: 'var(--text-secondary)' }}>Nenhuma avaliação registrada.</p> : null}
                {listaAvaliacoes.map(av => (
                  <div key={av.id} style={{ padding: '15px', background: 'rgba(255,255,255,0.05)', borderRadius: '8px', borderLeft: '3px solid var(--accent)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <strong>{av.tipo_escala}</strong>
                      <span style={{ fontSize: '0.85em', color: 'var(--text-secondary)' }}>{av.data}</span>
                    </div>
                    <h2 style={{ margin: '10px 0', color: 'var(--accent)' }}>Escore: {av.escore_total}</h2>
                    <p style={{ margin: 0 }}>Classificação: <strong>{av.classificacao}</strong></p>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AvaliacoesView;
